function handleProgressBar() {
  const progressBarFilled = document.querySelector('.progress-bar-filled');
  const currentTime = Date.now();
  let secondsPassed = ((currentTime - overallStartTime) / 1000 - 1.5).toFixed(0);

  if (isGenerating) {
    const activeTime = ((currentTime - startTime) / 1000).toFixed(0);

    // Add emoji dots animation to the progress text
    const emojiDots = ['💫', '✨', '🌟'];
