    const dotCount = Math.min(dotIndex + 1, maxDotCount);

    let dotPattern = '';
    for (let i = 0; i < dotCount; i++) {
      dotPattern += emojiDots[i % numDots] + ' ';
    }
    dotPattern += ' '.repeat(maxDotCount - dotCount);

